// SPDX-License-Identifier: MIT
pragma solidity 0.8.20;

contract PresaleMint {
    address private _owner;

    enum State { PresaleLive, SaleLive, SaleClosed }
    State public currentState = State.PresaleLive;

    mapping(address => bool) public presalerList;

    uint256 private _presaleAmountMinted;
    uint256 private _publicAmountMinted;

    error NotOwner();
    error InvalidState();
    error NotWhitelisted();

    constructor() {
        _owner = msg.sender;
    }

    modifier onlyOwner() {
        if (msg.sender != _owner) revert NotOwner();
        _;
    }

    function whitelist(address user, bool status) external onlyOwner {
        presalerList[user] = status;
    }

    function toggleSale() external onlyOwner {
        if (currentState == State.PresaleLive) {
            currentState = State.SaleLive;
        } else if (currentState == State.SaleLive) {
            currentState = State.SaleClosed;
            // Withdraw funds when sale closes
            payable(_owner).transfer(address(this).balance);
        }
    }

    function presaleBuy() external payable {
        require(msg.value > 0, "Must send ETH");
        if (currentState != State.PresaleLive) revert InvalidState();
        if (!presalerList[msg.sender]) revert NotWhitelisted();

        _presaleAmountMinted++;
    }

    function buy() external payable {
        require(msg.value > 0, "Must send ETH");
        if (currentState != State.SaleLive) revert InvalidState();

        _publicAmountMinted++;
    }

    function presaleAmountMinted() external view returns (uint256) {
        return _presaleAmountMinted;
    }

    function publicAmountMinted() external view returns (uint256) {
        return _publicAmountMinted;
    }
}
